# Parallel document loading: speed up ingestion for large corpora
# Each file is loaded in a separate thread; useful when loading is I/O-bound.

import concurrent.futures
from pathlib import Path
from langchain_community.document_loaders import (
    PyPDFLoader, TextLoader, BSHTMLLoader
)
from langchain_core.documents import Document


LOADER_MAP = {
    ".pdf": PyPDFLoader,
    ".html": BSHTMLLoader,
    ".htm": BSHTMLLoader,
    ".txt": TextLoader,
    ".md": TextLoader,
}


def load_file(file_path: str) -> list[Document]:
    ext = Path(file_path).suffix.lower()
    loader_cls = LOADER_MAP.get(ext)
    if loader_cls is None:
        print(f"Skipping unsupported format: {file_path}")
        return []
    try:
        return loader_cls(file_path).load()
    except Exception as e:
        print(f"Failed to load {file_path}: {e}")
        return []


def load_all_parallel(file_paths: list[str], max_workers: int = 8) -> list[Document]:
    """Load all files concurrently using a thread pool."""
    all_docs: list[Document] = []
    with concurrent.futures.ThreadPoolExecutor(max_workers=max_workers) as executor:
        futures = {executor.submit(load_file, p): p for p in file_paths}
        for future in concurrent.futures.as_completed(futures):
            path = futures[future]
            try:
                docs = future.result()
                all_docs.extend(docs)
            except Exception as e:
                print(f"Unexpected error for {path}: {e}")
    return all_docs


# Example: load 500 files with 8 threads
import glob
files = glob.glob("docs/**/*.*", recursive=True)
docs = load_all_parallel(files)
print(f"Total docs loaded: {len(docs)}")
